import sys

def main():
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    # Find the rectangle of cookies
    # Find the min and max row and column with cookies
    min_row, max_row = H, 0
    min_col, max_col = W, 0

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                min_row = min(min_row, i)
                max_row = max(max_row, i)
                min_col = min(min_col, j)
                max_col = max(max_col, j)

    # Check if the rectangle has at least 2 rows and 2 columns
    if (max_row - min_row + 1 < 2) or (max_col - min_col + 1 < 2):
        print("Invalid grid configuration")
        return

    # Find the missing cookie (the one that was eaten)
    for i in range(min_row, max_row + 1):
        for j in range(min_col, max_col + 1):
            if grid[i][j] == '.':
                print(i + 1, j + 1)
                return

if __name__ == "__main__":
    main()
